import React from 'react';
import Particles from 'react-tsparticles';

const ParticleBackground = () => {
  return (
    <Particles
      id="tsparticles"
      options={{
        // Customize particle options here
        particles: {
          number: { value: 80 },
          size: { value: 3 },
          color: { value: '#ffffff' },
          line_linked: { color: '#ffffff' },
        },
      }}
    />
  );
};

export default ParticleBackground;
